    /// <summary>
    /// Utility to redact sensitive information before logging.
    /// </summary>
    public static class LogSanitizer
    {
        private static readonly HashSet<string> SensitiveHeaders = new(StringComparer.OrdinalIgnoreCase)
        {
            "Authorization", "Cookie", "Set-Cookie", "X-Api-Key",
            "X-Auth-Token", "Proxy-Authorization"
        };

        private static readonly HashSet<string> SensitiveFields = new(StringComparer.OrdinalIgnoreCase)
        {
            "password", "ssn", "creditcardnumber", "creditcard",
            "credit_card", "cvv", "token", "secret", "apikey"
        };

        public static Dictionary<string, string> SanitizeHeaders(IHeaderDictionary headers)
        {
            var sanitized = new Dictionary<string, string>();
            foreach (var header in headers)
            {
                if (SensitiveHeaders.Contains(header.Key))
                {
                    sanitized[header.Key] = RedactValue(header.Value.ToString());
                }
                else
                {
                    sanitized[header.Key] = header.Value.ToString();
                }
            }
            return sanitized;
        }

        public static string RedactValue(string value)
        {
            if (string.IsNullOrEmpty(value)) return "[EMPTY]";
            if (value.Length <= 4) return "[REDACTED]";
            return $"[REDACTED...{value[^4..]}]";
        }

        public static Dictionary<string, object> SanitizeObject(object obj)
        {
            if (obj == null) return new Dictionary<string, object>();

            var result = new Dictionary<string, object>();
            foreach (var prop in obj.GetType().GetProperties())
            {
                var value = prop.GetValue(obj);
                if (SensitiveFields.Contains(prop.Name))
                {
                    result[prop.Name] = "[REDACTED]";
                }
                else
                {
                    result[prop.Name] = value;
                }
            }
            return result;
        }

        public static string MaskEmail(string email)
        {
            if (string.IsNullOrEmpty(email)) return "[EMPTY]";
            var parts = email.Split('@');
            if (parts.Length != 2) return "[INVALID_EMAIL]";
            var localPart = parts[0];
            var masked = localPart.Length > 2
                ? $"{localPart[0]}***{localPart[^1]}"
                : "***";
            return $"{masked}@{parts[1]}";
        }
    }

    /// <summary>
    /// Correlation context for tracking requests across services.
    /// </summary>
    public class RequestCorrelation
    {
        public string CorrelationId { get; set; }
        public string RequestId { get; set; }
        public string UserId { get; set; } // Use opaque user ID, never PII
        public DateTime Timestamp { get; set; }

        public static RequestCorrelation FromRequest(HttpRequest req)
        {
            return new RequestCorrelation
            {
                CorrelationId = req.Headers["X-Correlation-Id"].FirstOrDefault() ?? Guid.NewGuid().ToString(),
                RequestId = Guid.NewGuid().ToString(),
                UserId = req.HttpContext?.User?.FindFirst("sub")?.Value ?? "anonymous",
                Timestamp = DateTime.UtcNow
            };
        }
    }

    public static class SecureFunction
    {
        [FunctionName("SecureProcessOrder")]
        public static async Task<IActionResult> Run(
            [HttpTrigger(AuthorizationLevel.Function, "post", Route = "orders")] HttpRequest req,
            ILogger log)
        {
            var correlation = RequestCorrelation.FromRequest(req);

            // ✅ Log safe metadata only
            log.LogInformation(
                "Request received. CorrelationId: {CorrelationId}, RequestId: {RequestId}, " +
                "Method: {Method}, Path: {Path}, ContentLength: {ContentLength}, " +
                "ContentType: {ContentType}, UserId: {UserId}",
                correlation.CorrelationId,
                correlation.RequestId,
                req.Method,
                req.Path,
                req.ContentLength,
                req.ContentType,
                correlation.UserId);

            // ✅ Log sanitized headers (sensitive ones are redacted)
            var sanitizedHeaders = LogSanitizer.SanitizeHeaders(req.Headers);
            log.LogDebug(
                "Sanitized headers for {CorrelationId}: {Headers}",
                correlation.CorrelationId,
                JsonConvert.SerializeObject(sanitizedHeaders));

            string requestBody;
            try
            {
                req.EnableBuffering();
                requestBody = await new StreamReader(req.Body).ReadToEndAsync();
                req.Body.Position = 0;
            }
            catch (Exception ex)
            {
                log.LogError(ex,
                    "Failed to read request body. CorrelationId: {CorrelationId}",
                    correlation.CorrelationId);
                return new BadRequestObjectResult(new { error = "Invalid request body" });
            }

            // ✅ Log body size only, never content
            log.LogInformation(
                "Request body read. CorrelationId: {CorrelationId}, BodyLength: {BodyLength}",
                correlation.CorrelationId,
                requestBody?.Length ?? 0);

            OrderRequest order;
            try
            {
                order = JsonConvert.DeserializeObject<OrderRequest>(requestBody);
                if (order == null)
                {
                    log.LogWarning(
                        "Deserialized order is null. CorrelationId: {CorrelationId}",
                        correlation.CorrelationId);
                    return new BadRequestObjectResult(new { error = "Invalid order data" });
                }
            }
            catch (JsonException ex)
            {
                log.LogWarning(ex,
                    "JSON deserialization failed. CorrelationId: {CorrelationId}, ErrorPath: {Path}",
                    correlation.CorrelationId,
                    ex.Path);
                return new BadRequestObjectResult(new { error = "Malformed JSON" });
            }

            // ✅ Log only non-sensitive business data
            log.LogInformation(
                "Order parsed. CorrelationId: {CorrelationId}, ProductId: {ProductId}, " +
                "Quantity: {Quantity}, MaskedEmail: {Email}",
                correlation.CorrelationId,
                order.ProductId,
                order.Quantity,
                LogSanitizer.MaskEmail(order.Email));

            try
            {
                // ✅ Log query structure without parameter values
                var orderId = await ExecuteOrderInsertAsync(order, correlation, log);

                log.LogInformation(
                    "Order created successfully. CorrelationId: {CorrelationId}, OrderId: {OrderId}",
                    correlation.CorrelationId,
                    orderId);

                return new OkObjectResult(new
                {
                    message = "Order processed",
                    orderId,
                    correlationId = correlation.CorrelationId
                });
            }
            catch (SqlException ex)
            {
                // ✅ Log SQL error code and message but NOT parameter values
                log.LogError(
                    "Database error. CorrelationId: {CorrelationId}, SqlErrorNumber: {ErrorNumber}, " +
                    "SqlState: {State}, SqlMessage: {Message}",
                    correlation.CorrelationId,
                    ex.Number,
                    ex.State,
                    ex.Message);

                return new StatusCodeResult(500);
            }
            catch (Exception ex)
            {
                // ✅ Log exception details without request body or sensitive context
                log.LogError(ex,
                    "Unhandled error processing order. CorrelationId: {CorrelationId}, " +
                    "RequestId: {RequestId}, ExceptionType: {ExceptionType}, " +
                    "ProductId: {ProductId}",
                    correlation.CorrelationId,
                    correlation.RequestId,
                    ex.GetType().FullName,
                    order.ProductId);

                return new StatusCodeResult(500);
            }
        }

        private static async Task<string> ExecuteOrderInsertAsync(
            OrderRequest order,
            RequestCorrelation correlation,
            ILogger log)
        {
            var connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
            // ✅ NEVER log the connection string

            const string query = @"
                INSERT INTO Orders (Email, ProductId, Quantity, CreatedAt, CorrelationId)
                OUTPUT INSERTED.OrderId
                VALUES (@Email, @ProductId, @Quantity, @CreatedAt, @CorrelationId)";

            // ✅ Log query template and parameter names only (not values)
            log.LogDebug(
                "Executing query. CorrelationId: {CorrelationId}, QueryTemplate: {Query}, " +
                "Parameters: [@Email, @ProductId, @Quantity, @CreatedAt, @CorrelationId]",
                correlation.CorrelationId,
                "INSERT INTO Orders ... VALUES (...)");

            // ✅ Use parameterized queries - never string concatenation
            using var connection = new SqlConnection(connectionString);
            await connection.OpenAsync();

            using var command = new SqlCommand(query, connection);
            command.Parameters.AddWithValue("@Email", order.Email);
            command.Parameters.AddWithValue("@ProductId", order.ProductId);
            command.Parameters.AddWithValue("@Quantity", order.Quantity);
            command.Parameters.AddWithValue("@CreatedAt", DateTime.UtcNow);
            command.Parameters.AddWithValue("@CorrelationId", correlation.CorrelationId);

            var startTime = DateTime.UtcNow;
            var result = await command.ExecuteScalarAsync();
            var elapsed = DateTime.UtcNow - startTime;

            // ✅ Log performance metrics
            log.LogInformation(
                "Query executed. CorrelationId: {CorrelationId}, DurationMs: {DurationMs}",
                correlation.CorrelationId,
                elapsed.TotalMilliseconds);

            return result?.ToString();
        }
    }

